// ===== DPro デイリーニュース取得 =====
const DPRO_BASE = 'https://YOUR_WORKER_NAME.workers.dev'; // ← Cloudflare WorkerのURLに変更

async function dproGet(path, params) {
  let qs = '';
  if (params) {
    const parts = [];
    for (const [k, v] of Object.entries(params)) {
      if (v != null) parts.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v)));
    }
    if (parts.length) qs = '?' + parts.join('&');
  }
  const fullUrl = DPRO_BASE + path + qs;
  const res = await $http.request({ method: 'GET', url: fullUrl });
  return res;
}

// 1. 媒体ID取得
const appsRaw = await dproGet('/api/v1/apps');
const appList = Array.isArray(appsRaw) ? appsRaw : (appsRaw.data || appsRaw.apps || []);
const igApp = appList.find(function(a) { return /instagram|facebook/i.test(JSON.stringify(a)); });
const ytApp = appList.find(function(a) { return /youtube/i.test(JSON.stringify(a)); });
const igId = igApp ? (igApp.id || igApp.app_id) : null;
const ytId = ytApp ? (ytApp.id || ytApp.app_id) : null;

// 2. ジャンルID取得
const GENRE_QUERIES = [
  { label: '毛穴/シミ/シワ', q: '毛穴' },
  { label: 'ヒザ系', q: 'ヒザ' },
  { label: '子供サプリ', q: '成長' },
  { label: '女性体臭', q: '体臭' }
];
const genreIds = {};
for (const gq of GENRE_QUERIES) {
  try {
    const r = await dproGet('/api/v1/genres', { q: gq.q });
    const list = Array.isArray(r) ? r : (r.data || r.genres || []);
    genreIds[gq.label] = list.length > 0 ? (list[0].id || list[0].genre_id) : null;
  } catch(e) {
    genreIds[gq.label] = null;
  }
}

// 3. 各ジャンル x 媒体でTOP3取得
const GENRE_LABELS = ['毛穴/シミ/シワ', 'ヒザ系', '子供サプリ', '女性体臭', '全ジャンル'];
const MEDIAS = [
  { label: '📸Instagram', id: igId },
  { label: '🎬YouTube', id: ytId }
];
const newsData = [];
for (const genreLabel of GENRE_LABELS) {
  for (const media of MEDIAS) {
    const params = { app_id: media.id, sort: 'ad_cost_diff_desc', limit: 3 };
    if (genreLabel !== '全ジャンル' && genreIds[genreLabel]) {
      params.genre_id = genreIds[genreLabel];
    }
    let items = [];
    try {
      const r = await dproGet('/api/v1/items', params);
      items = Array.isArray(r) ? r : (r.data || r.items || []);
    } catch(e) { items = []; }
    newsData.push({ genre: genreLabel, media: media.label, items: items });
  }
}

// 4. 今日のハイライトを算出
let hlGenre = '—', hlName = '—', hlDiff = 0;
for (const nd of newsData) {
  for (const item of nd.items) {
    const diff = Number(item.ad_cost_diff || item.ad_cost_diff_30d || 0);
    if (diff > hlDiff) {
      hlDiff = diff;
      hlGenre = nd.genre;
      hlName = item.product_name || item.name || '—';
    }
  }
}

// 5. メインメッセージ組み立て
const today = new Date().toLocaleDateString('ja-JP', {
  year: 'numeric', month: '2-digit', day: '2-digit', timeZone: 'Asia/Tokyo'
});
function topName(genre, media) {
  const nd = newsData.find(function(d) { return d.genre === genre && d.media === media; });
  if (!nd || !nd.items.length) return '—';
  return nd.items[0].product_name || nd.items[0].name || '—';
}
const mainText = '📊 *DPro デイリーニュース｜' + today + '*\n\n'
  + '\t\t📸Instagram\t🎬YouTube\n'
  + '━━━━━━━━━━━━━━━━━━━━━━━━\n'
  + '毛穴/シミ/シワ\t▲' + topName('毛穴/シミ/シワ','📸Instagram') + '\t▲' + topName('毛穴/シミ/シワ','🎬YouTube') + '\n'
  + 'ヒザ系\t\t▲' + topName('ヒザ系','📸Instagram') + '\t▲' + topName('ヒザ系','🎬YouTube') + '\n'
  + '子供サプリ\t▲' + topName('子供サプリ','📸Instagram') + '\t▲' + topName('子供サプリ','🎬YouTube') + '\n'
  + '女性体臭\t\t▲' + topName('女性体臭','📸Instagram') + '\t▲' + topName('女性体臭','🎬YouTube') + '\n'
  + '━━━━━━━━━━━━━━━━━━━━━━━━\n'
  + '💡 今日の注目: *' + hlGenre + '* — ' + hlName + '\n\n'
  + '詳細 → 🧵 スレッドへ';

return [{ json: { mainText: mainText, newsData: newsData } }];

// スレッドメッセージ一覧を生成
const newsData = $input.first().json.newsData;
const mainTs = $('Slackメイン投稿').first().json.ts;
const CHANNEL = 'C0AMYLU2W5D';

const threadMessages = [];
for (const nd of newsData) {
  if (!nd.items || nd.items.length === 0) continue;
  const lines = ['【' + nd.media + ' × ' + nd.genre + '】直近30日トレンド', ''];
  nd.items.forEach(function(item, i) {
    const name = item.product_name || item.name || '商品名不明';
    const diff = Number(item.ad_cost_diff || item.ad_cost_diff_30d || 0);
    const diffStr = diff >= 1000000
      ? '▲¥' + (diff / 1000000).toFixed(1) + 'M'
      : '▲¥' + (diff / 1000).toFixed(0) + 'K';
    const hook = item.narration_text || item.copy_text || item.description || '';
    lines.push((i + 1) + '. ' + diffStr + '｜' + name);
    if (hook) lines.push('   フック: 「' + hook.slice(0, 60) + (hook.length > 60 ? '…' : '') + '」');
  });
  lines.push('');
  threadMessages.push({
    channel: CHANNEL,
    thread_ts: mainTs,
    text: lines.join('\n')
  });
}
return threadMessages.map(function(m) { return { json: m }; });
